sql:
SELECT age_range_name
FROM age_ranges
WHERE age_range_id = '0';

SELECT smartwatch_likelihood
FROM smartwatch_preferences
WHERE respondent_id = '1';

SELECT respondent_id, smartwatch_likelihood
FROM smartwatch_preferences
WHERE smartwatch_likelihood = 'Very likely';

SELECT smartwatch_likelihood, COUNT(respondent_id) AS respondent_count
FROM smartwatch_preferences
GROUP BY smartwatch_likelihood;

SELECT COUNT(*) AS high_intent_count
FROM smartwatch_preferences
WHERE purchase_intent = 'High';

SELECT COUNT(*) 
FROM weather_checking_habits 
WHERE checks_weather = 'Yes' AND check_method = '0';

SELECT checks_weather
FROM weather_checking_habits
WHERE respondent_id = '0';

SELECT DISTINCT check_method
FROM weather_checking_habits
WHERE check_method IS NOT NULL;

SELECT COUNT(respondent_id) AS total_respondents_with_smartwatch_likelihood
FROM smartwatch_preferences
WHERE smartwatch_likelihood IS NOT NULL;

SELECT likelihood_name
FROM smartwatch_likelihoods
WHERE likelihood_id = '0';

SELECT checks_weather, COUNT(frequency_per_day) AS daily_weather_check_count
FROM weather_checking_habits
WHERE respondent_id = '0';
